-- complete data import script for montgomery county voter access analysis
-- populates all tables from csv files generated by python processing

-- population centers table import
-- stores population-weighted centroids for each block group
truncate population_centers cascade;

create temp table temp_pop_centers (
    statefp text,
    countyfp text,
    tractce text,
    blkgrpce text,
    population text,
    latitude text,
    longitude text,
    geoid text,
    geometry text
);

copy temp_pop_centers from '/tmp/accessibility_scores_enhanced_complete.csv'
delimiter ','
csv header;

insert into population_centers (geoid, population, latitude, longitude)
select distinct 
    geoid,
    nullif(population, 'NA')::integer,
    nullif(latitude, 'NA')::double precision,
    nullif(longitude, 'NA')::double precision
from temp_pop_centers
where geoid is not null 
  and geoid like '1101%';

update population_centers 
set geom = st_setsrid(st_makepoint(longitude, latitude), 4326)
where latitude is not null and longitude is not null;

drop table temp_pop_centers;

select count(*) as population_centers_count from population_centers;

-- accessibility scores table import
-- comprehensive distance and walkability metrics for each population center
truncate accessibility_scores cascade;

create temp table temp_accessibility (
    statefp text,
    countyfp text,
    tractce text,
    blkgrpce text,
    population text,
    latitude text,
    longitude text,
    geoid text,
    geometry text,
    min_dist_to_poll_miles text,
    nearest_polling_idx text,
    min_manhattan_dist_miles text,
    min_dist_to_civic_center_miles text,
    dist_to_city_hall_miles text,
    min_dist_to_poll_miles_norm text,
    min_manhattan_dist_miles_norm text,
    min_dist_to_civic_center_miles_norm text,
    accessibility_score text,
    accessibility_category text,
    min_network_dist_miles text,
    nearest_poll_network_idx text,
    driving_to_euclidean_ratio text,
    driving_euclidean_diff_miles text,
    min_walking_dist_miles text,
    nearest_poll_walking_idx text,
    osrm_walking_to_euclidean_ratio text,
    min_google_walking_dist_miles text,
    nearest_poll_google_walking_idx text,
    google_walking_to_euclidean_ratio text,
    osrm_walking_to_driving_ratio text,
    google_to_osrm_walking_ratio text,
    google_walking_to_driving_ratio text,
    osm_has_sidewalk text,
    osm_sidewalk_count text,
    osm_total_segments text,
    osm_sidewalk_pct text,
    walkability_score text,
    walkability_category text
);

copy temp_accessibility from '/tmp/accessibility_scores_enhanced_complete.csv'
delimiter ','
csv header;

insert into accessibility_scores (
    geoid,
    euclidean_dist_miles,
    nearest_poll_id,
    manhattan_dist_miles,
    dist_to_civic_center_miles,
    dist_to_city_hall_miles,
    osrm_driving_miles,
    nearest_poll_osrm_driving_idx,
    driving_to_euclidean_ratio,
    driving_euclidean_diff_miles,
    osrm_walking_miles,
    nearest_poll_osrm_walking_idx,
    osrm_walking_to_euclidean_ratio,
    google_walking_miles,
    nearest_poll_google_walking_idx,
    google_walking_to_euclidean_ratio,
    osrm_walking_to_driving_ratio,
    google_to_osrm_walking_ratio,
    google_walking_to_driving_ratio,
    osm_has_sidewalk,
    osm_sidewalk_count,
    osm_total_segments,
    osm_sidewalk_pct,
    walkability_score,
    walkability_category
)
select 
    geoid,
    nullif(min_dist_to_poll_miles, 'NA')::double precision,
    nullif(nearest_polling_idx, 'NA')::integer,
    nullif(min_manhattan_dist_miles, 'NA')::double precision,
    nullif(min_dist_to_civic_center_miles, 'NA')::double precision,
    nullif(dist_to_city_hall_miles, 'NA')::double precision,
    nullif(min_network_dist_miles, 'NA')::double precision,
    nullif(nearest_poll_network_idx, 'NA')::integer,
    nullif(driving_to_euclidean_ratio, 'NA')::double precision,
    nullif(driving_euclidean_diff_miles, 'NA')::double precision,
    nullif(min_walking_dist_miles, 'NA')::double precision,
    nullif(nearest_poll_walking_idx, 'NA')::integer,
    nullif(osrm_walking_to_euclidean_ratio, 'NA')::double precision,
    nullif(min_google_walking_dist_miles, 'NA')::double precision,
    nullif(nearest_poll_google_walking_idx, 'NA')::integer,
    nullif(google_walking_to_euclidean_ratio, 'NA')::double precision,
    nullif(osrm_walking_to_driving_ratio, 'NA')::double precision,
    nullif(google_to_osrm_walking_ratio, 'NA')::double precision,
    nullif(google_walking_to_driving_ratio, 'NA')::double precision,
    nullif(osm_has_sidewalk, 'NA')::boolean,
    nullif(osm_sidewalk_count, 'NA')::integer,
    nullif(osm_total_segments, 'NA')::integer,
    nullif(osm_sidewalk_pct, 'NA')::double precision,
    nullif(walkability_score, 'NA')::double precision,
    walkability_category
from temp_accessibility
where geoid is not null
  and geoid like '1101%';

drop table temp_accessibility;

select count(*) as accessibility_count from accessibility_scores;

-- isochrone summary table import
-- aggregated metrics for walkable areas around each polling place
truncate isochrone_summary;

create temp table temp_isochrone (
    polling_place text,
    time_minutes text,
    area_sq_miles text,
    population_served text
);

copy temp_isochrone from '/tmp/polling_isochrone_summary.csv'
delimiter ','
csv header;

insert into isochrone_summary (polling_place_name, time_minutes, area_sq_miles, population_served)
select 
    polling_place,
    nullif(time_minutes, 'NA')::integer,
    nullif(area_sq_miles, 'NA')::double precision,
    nullif(population_served, 'NA')::integer
from temp_isochrone;

drop table temp_isochrone;

select count(*) as isochrone_count from isochrone_summary;

-- county turnout data insertion
