-- precinct boundaries for 2024 election
-- spatial boundaries of voting precincts after redistricting
truncate precincts_2024 cascade;

create temp table temp_precincts_2024 (like precincts_2024);
alter table temp_precincts_2024 add column unique_id text;
alter table temp_precincts_2024 add column county text;
alter table temp_precincts_2024 add column precinct text;

copy temp_precincts_2024 from '/tmp/montgomery_precinct_results_2024.csv'
delimiter ','
csv header;

insert into precincts_2024 (geoid, county_fips, county, name, state_fips)
select 
    unique_id,
    '101',
    county,
    precinct,
    '01'
from temp_precincts_2024
where unique_id is not null;

