union all
select 'precincts_2020', count(*) from precincts_2020
union all
select 'precincts_2024', count(*) from precincts_2024
union all
select 'election_results_2020', count(*) from election_results_2020
union all
select 'election_results_2024', count(*) from election_results_2024
union all
select 'vulnerability_index', count(*) from vulnerability_index;